    inline TypeId MakeTypeId(StringView name, TypeId parentId)
    {
        HE_ASSERT(HasFlag(parentId, TypeIdFlag));
        return FNV64::HashData(name.Data(), name.Size(), parentId) | TypeIdFlag;
    }

    constexpr bool IsTypeId(TypeId id)
    {
        return HasFlag(id, TypeIdFlag);
    }

    constexpr bool IsSignedIntegral(Type::Data::UnionTag t)
    {
        switch (t)
        {
            case Type::Data::UnionTag::Int8:
            case Type::Data::UnionTag::Int16:
            case Type::Data::UnionTag::Int32:
            case Type::Data::UnionTag::Int64:
                return true;
            default:
                return false;
        }
    }

    constexpr bool IsUnsignedIntegral(Type::Data::UnionTag t)
    {
        switch (t)
        {
            case Type::Data::UnionTag::Uint8:
            case Type::Data::UnionTag::Uint16:
            case Type::Data::UnionTag::Uint32:
            case Type::Data::UnionTag::Uint64:
                return true;
            default:
                return false;
        }
    }

    constexpr bool IsIntegral(Type::Data::UnionTag t)
    {
        return IsSignedIntegral(t) || IsUnsignedIntegral(t);
    }

    constexpr bool IsFloat(Type::Data::UnionTag t)
    {
        switch (t)
        {
            case Type::Data::UnionTag::Float32:
            case Type::Data::UnionTag::Float64:
                return true;
            default:
                return false;
        }
    }

    constexpr bool IsArithmetic(Type::Data::UnionTag t)
    {
        return IsIntegral(t) || IsFloat(t);
    }

    constexpr bool IsPointer(Type::Data::UnionTag t)
    {
        switch (t)
        {
            case Type::Data::UnionTag::Blob:
            case Type::Data::UnionTag::String:
            case Type::Data::UnionTag::List:
            case Type::Data::UnionTag::Struct:
            case Type::Data::UnionTag::Interface:
            case Type::Data::UnionTag::AnyPointer:
            case Type::Data::UnionTag::AnyStruct:
            case Type::Data::UnionTag::AnyList:
            case Type::Data::UnionTag::Parameter:
                return true;

            default:
                return false;
        }
    }

    inline bool IsPointer(const Type::Reader& t)
    {
        if (t.GetData().IsArray())
        {
            const Type::Reader elmType = t.GetData().GetArray().GetElementType();
            HE_ASSERT(!elmType.GetData().IsArray(), HE_MSG("Arrays of arrays are not supported"));
            return IsPointer(elmType);
        }

        return IsPointer(t.GetData().GetUnionTag());
    }

    // Returns the bit alignment requirements for a type
    inline uint32_t GetBitsInElementSize(ElementSize s)
    {
        switch (s)
        {
            case ElementSize::Void: return 0;
            case ElementSize::Bit: return 1;
            case ElementSize::Byte: return 8;
            case ElementSize::TwoBytes: return 16;
            case ElementSize::FourBytes: return 32;
            case ElementSize::EightBytes: return 64;
            case ElementSize::Pointer: return 64;
            case ElementSize::Composite: return 0;
            case ElementSize::_Count: break;
        }

        HE_ASSERT(false, HE_MSG("Unknown type kind"));
        return 0;
    }

    // Returns the bit alignment requirements for a type
    inline uint32_t GetTypeAlign(const Type::Reader& t)
    {
        switch (t.GetData().GetUnionTag())
        {
            case Type::Data::UnionTag::Void: return 0;
            case Type::Data::UnionTag::Bool: return 1;
            case Type::Data::UnionTag::Int8: return 8;
            case Type::Data::UnionTag::Int16: return 16;
            case Type::Data::UnionTag::Int32: return 32;
            case Type::Data::UnionTag::Int64: return 64;
            case Type::Data::UnionTag::Uint8: return 8;
            case Type::Data::UnionTag::Uint16: return 16;
            case Type::Data::UnionTag::Uint32: return 32;
            case Type::Data::UnionTag::Uint64: return 64;
            case Type::Data::UnionTag::Float32: return 32;
            case Type::Data::UnionTag::Float64: return 64;
            case Type::Data::UnionTag::Array: return GetTypeAlign(t.GetData().GetArray().GetElementType());
            case Type::Data::UnionTag::Blob: return 64; // pointer
            case Type::Data::UnionTag::String: return 64; // pointer
            case Type::Data::UnionTag::List: return 64; // pointer
            case Type::Data::UnionTag::Enum: return 16; // uint16
            case Type::Data::UnionTag::Struct: return 64; // pointer
            case Type::Data::UnionTag::Interface: return 64; // pointer
            case Type::Data::UnionTag::AnyPointer: return 64; // pointer
            case Type::Data::UnionTag::AnyStruct: return 64; // pointer
            case Type::Data::UnionTag::AnyList: return 64; // pointer
            case Type::Data::UnionTag::Parameter: return 64; // pointer
        }

        HE_ASSERT(false, HE_MSG("Unknown type kind"));
        return 0;
    }

    // Returns the size of a type in bits
    inline uint32_t GetTypeSize(const Type::Reader& type)
    {
        const uint32_t align = GetTypeAlign(type);
        const uint32_t count = type.GetData().IsArray() ? type.GetData().GetArray().GetSize() : 1;
        return align * count;
    }

    constexpr ElementSize GetTypeElementSize(Type::Data::UnionTag t)
    {
        switch (t)
        {
            case Type::Data::UnionTag::Void: return ElementSize::Void;
            case Type::Data::UnionTag::Bool: return ElementSize::Bit;
            case Type::Data::UnionTag::Int8: return ElementSize::Byte;
            case Type::Data::UnionTag::Int16: return ElementSize::TwoBytes;
            case Type::Data::UnionTag::Int32: return ElementSize::FourBytes;
            case Type::Data::UnionTag::Int64: return ElementSize::EightBytes;
            case Type::Data::UnionTag::Uint8: return ElementSize::Byte;
            case Type::Data::UnionTag::Uint16: return ElementSize::TwoBytes;
            case Type::Data::UnionTag::Uint32: return ElementSize::FourBytes;
            case Type::Data::UnionTag::Uint64: return ElementSize::EightBytes;
            case Type::Data::UnionTag::Float32: return ElementSize::FourBytes;
            case Type::Data::UnionTag::Float64: return ElementSize::EightBytes;
            case Type::Data::UnionTag::Array: return ElementSize::Void; // Lists of arrays are not supported
            case Type::Data::UnionTag::Blob: return ElementSize::Pointer;
            case Type::Data::UnionTag::String: return ElementSize::Pointer;
            case Type::Data::UnionTag::List: return ElementSize::Pointer;
            case Type::Data::UnionTag::Enum: return ElementSize::TwoBytes;
            case Type::Data::UnionTag::Struct: return ElementSize::Composite;
            case Type::Data::UnionTag::Interface: return ElementSize::Pointer;
            case Type::Data::UnionTag::AnyPointer: return ElementSize::Pointer;
            case Type::Data::UnionTag::AnyStruct: return ElementSize::Pointer;
            case Type::Data::UnionTag::AnyList: return ElementSize::Pointer;
            case Type::Data::UnionTag::Parameter: return ElementSize::Pointer;
        }

        HE_ASSERT(false, HE_MSG("Unknown type kind"));
        return ElementSize::Void;
    }

    inline ElementSize GetTypeElementSize(const Type::Reader& t)
    {
        return GetTypeElementSize(t.GetData().GetUnionTag());
    }

    inline Attribute::Reader FindAttribute(List<Attribute>::Reader attributes, TypeId id)
    {
        for (Attribute::Reader attribute : attributes)
        {
            if (attribute.GetId() == id)
                return attribute;
        }

        return {};
    }

    template <typename T>
    inline Attribute::Reader FindAttribute(List<Attribute>::Reader attributes)
    {
        return FindAttribute(attributes, T::Id);
    }

    inline bool HasAttribute(List<Attribute>::Reader attributes, TypeId id)
    {
        return FindAttribute(attributes, id).IsValid();
    }

    template <typename T>
    inline bool HasAttribute(List<Attribute>::Reader attributes)
    {
        return HasAttribute(attributes, T::Id);
    }

    inline Declaration::Reader GetSchema(const DeclInfo& info)
    {
        const DeclInfo& I = Declaration::DeclInfo;
        return Declaration::Reader(StructReader(info.schema, I.dataWordSize, I.pointerCount));
    }

    inline Field::Reader FindFieldByName(StringView name, Declaration::Data::Struct::Reader st)
    {
        for (Field::Reader field : st.GetFields())
        {
            if (field.GetName() == name)
                return field;
        }

        return {};
    }

    template <typename T>
    inline Field::Reader FindFieldByName(StringView name)
    {
        const Declaration::Reader decl = GetSchema(T::DeclInfo);
        return FindFieldByName(name, decl.GetData().GetStruct());
    }

    inline Field::Reader FindFieldByUnionTag(uint16_t unionTag, Declaration::Data::Struct::Reader st)
    {
        for (Field::Reader field : st.GetFields())
        {
            if (field.GetUnionTag() == unionTag)
                return field;
        }

        return {};
    }

    void FillUuidV4(Uuid::Builder builder);

    const DeclInfo* FindDependency(const DeclInfo& info, TypeId id);

    class SchemaVisitor
    {
    public:
        virtual ~SchemaVisitor() = default;

        virtual bool Visit(Declaration::Reader schema) { return VisitDecl(schema, {}); }

    protected:
        virtual bool VisitDecl(Declaration::Reader decl, Declaration::Reader scope);

        virtual bool VisitFile(Declaration::Reader decl);
        virtual bool VisitAttribute(Declaration::Reader decl, Declaration::Reader scope) { HE_UNUSED(decl, scope); return true; }
        virtual bool VisitConstant(Declaration::Reader decl, Declaration::Reader scope) { HE_UNUSED(decl, scope); return true; }

        virtual bool VisitEnum(Declaration::Reader decl, Declaration::Reader scope);
        virtual bool VisitEnumerator(Enumerator::Reader enumerator, Declaration::Reader scope) { HE_UNUSED(enumerator, scope); return true; }

        virtual bool VisitInterface(Declaration::Reader decl, Declaration::Reader scope);
        virtual bool VisitMethod(Method::Reader method, Declaration::Reader scope) { HE_UNUSED(method, scope); return true; }

        virtual bool VisitStruct(Declaration::Reader decl, Declaration::Reader scope);
        virtual bool VisitField(Field::Reader field, Declaration::Reader scope);
        virtual bool VisitNormalField(Field::Reader field, Declaration::Reader scope) { HE_UNUSED(field, scope); return true; }
        virtual bool VisitGroupField(Field::Reader field, Declaration::Reader scope) { HE_UNUSED(field, scope); return true; }
        virtual bool VisitUnionField(Field::Reader field, Declaration::Reader scope) { HE_UNUSED(field, scope); return true; }

    protected:
        Declaration::Reader m_schema;
    };

    class StructVisitor
    {
    public:
        struct EnumValueTag {};

    public:
        virtual ~StructVisitor() = default;

        void Visit(StructReader data, const DeclInfo& declInfo) { VisitStruct(data, declInfo); }

    protected:
        // This section has functions that child classes are likely to override.

        virtual void VisitNormalField(StructReader data, Field::Reader field, const DeclInfo& scope);
        virtual void VisitGroupField(StructReader data, Field::Reader field, const DeclInfo& scope);
        virtual void VisitUnionField(StructReader data, Field::Reader field, const DeclInfo& scope);

        virtual void VisitValue(bool value, Type::Reader type, const DeclInfo& scope) { HE_UNUSED(value, type, scope); }
        virtual void VisitValue(int8_t value, Type::Reader type, const DeclInfo& scope) { HE_UNUSED(value, type, scope); }
        virtual void VisitValue(int16_t value, Type::Reader type, const DeclInfo& scope) { HE_UNUSED(value, type, scope); }
        virtual void VisitValue(int32_t value, Type::Reader type, const DeclInfo& scope) { HE_UNUSED(value, type, scope); }
        virtual void VisitValue(int64_t value, Type::Reader type, const DeclInfo& scope) { HE_UNUSED(value, type, scope); }
        virtual void VisitValue(uint8_t value, Type::Reader type, const DeclInfo& scope) { HE_UNUSED(value, type, scope); }
        virtual void VisitValue(uint16_t value, Type::Reader type, const DeclInfo& scope) { HE_UNUSED(value, type, scope); }
        virtual void VisitValue(uint32_t value, Type::Reader type, const DeclInfo& scope) { HE_UNUSED(value, type, scope); }
        virtual void VisitValue(uint64_t value, Type::Reader type, const DeclInfo& scope) { HE_UNUSED(value, type, scope); }
        virtual void VisitValue(float value, Type::Reader type, const DeclInfo& scope) { HE_UNUSED(value, type, scope); }
        virtual void VisitValue(double value, Type::Reader type, const DeclInfo& scope) { HE_UNUSED(value, type, scope); }
        virtual void VisitValue(Blob::Reader value, Type::Reader type, const DeclInfo& scope) { HE_UNUSED(value, type, scope); }
        virtual void VisitValue(String::Reader value, Type::Reader type, const DeclInfo& scope) { HE_UNUSED(value, type, scope); }
        virtual void VisitValue(EnumValueTag, uint16_t value, Type::Reader type, const DeclInfo& scope) { HE_UNUSED(value, type, scope); }

        virtual void VisitAnyPointer(PointerReader ptr, Type::Reader type, const DeclInfo& scope) { HE_UNUSED(ptr, type, scope); }
        virtual void VisitAnyStruct(PointerReader ptr, Type::Reader type, const DeclInfo& scope) { HE_UNUSED(ptr, type, scope); }
        virtual void VisitAnyList(PointerReader ptr, Type::Reader type, const DeclInfo& scope) { HE_UNUSED(ptr, type, scope); }

    protected:
        // This section has functions that child classes are less likely to override.
        // However, in some advanced cases it may be useful to do so.

        virtual void VisitStruct(StructReader data, const DeclInfo& info);
        virtual void VisitField(StructReader data, Field::Reader field, const DeclInfo& scope);

        virtual void VisitValue(Value::Reader data, Type::Reader type, const DeclInfo& scope);
        virtual void VisitValue(StructReader data, Type::Reader type, uint16_t index, uint32_t dataOffset, const DeclInfo& scope);
        virtual void VisitValue(ListReader data, Type::Reader elementType, uint32_t index, const DeclInfo& scope);

        virtual void VisitArrayValue(StructReader data, Type::Reader elementType, uint16_t index, uint32_t dataOffset, uint16_t size, const DeclInfo& scope);
        virtual void VisitListValue(ListReader data, Type::Reader elementType, const DeclInfo& scope);

        virtual bool ShouldVisitNormalField(StructReader data, Field::Reader field, const DeclInfo& scope);
        virtual bool ShouldVisitGroupField(StructReader data, Field::Reader field, const DeclInfo& scope);
        virtual bool ShouldVisitUnionField(StructReader data, Field::Reader field, const DeclInfo& scope);

        virtual bool AnyGroupFieldSet(StructReader data, Field::Reader field, const DeclInfo& scope);
        virtual bool IsUnionFieldSet(StructReader data, Field::Reader field, const DeclInfo& scope);
        virtual bool IsNormalFieldSet(StructReader data, Field::Reader field, const DeclInfo& scope);

    protected:
        const DeclInfo* FindGroupOrUnionInfo(Field::Reader field, const DeclInfo& scope);

    protected:
        Declaration::Reader m_schema;
    };
